import{_ as a,o as r,c as o,ae as i,j as t,a as l}from"./chunks/framework.CbfcRfVi.js";const h=JSON.parse('{"title":"Key information","description":"","frontmatter":{},"headers":[],"relativePath":"ps5/information.md","filePath":"ps5/information.md","lastUpdated":1777892371000}'),s={name:"ps5/information.md"};function n(d,e,p,c,u,m){return r(),o("div",null,[...e[0]||(e[0]=[i('<p><a href="/playstation-linux-tutorial/start.html">Go back.</a></p><h1 id="key-information" tabindex="-1">Key information <a class="header-anchor" href="#key-information" aria-label="Permalink to &quot;Key information&quot;">​</a></h1><p>This tutorial will cover how to install Linux on your PS5. It is created to make it easier for people to install linux on their consoles.</p><div class="note custom-block github-alert"><p class="custom-block-title">Will this affect my games? can it reverse it?</p><p>All your info should stay intact because you will install it on a seperate M.2 drive.</p></div><details class="details custom-block"><summary>Which consoles are compatible?</summary><p>ps5-linux is currently only supported on PS5 Phat on 3.xx and 4.xx firmwares</p><table tabindex="0"><thead><tr><th>Firmware</th><th>M.2</th></tr></thead><tbody><tr><td>4.51</td><td>✔️</td></tr><tr><td>4.50</td><td>✔️</td></tr><tr><td>4.03</td><td>✔️</td></tr><tr><td>4.02</td><td>✔️</td></tr><tr><td>4.00</td><td>✔️</td></tr><tr><td>3.21</td><td>❌</td></tr><tr><td>3.20</td><td>❌</td></tr><tr><td>3.10</td><td>❌</td></tr><tr><td>3.00</td><td>❌</td></tr></tbody></table><ul><li><p>Support for 1.xx and 2.xx firmwares may be added in the future, but we will not prioritize this effort.</p></li><li><p>Support for 5.xx firmwares may be added in the future, but for those firmwares, Linux will run within the GameOS VM, thus it will have less features (still unknown what limitations there will be) and it may not perform as good.</p></li></ul><p>If you want to update to a specific firmware, <a href="https://darthsternie.net/ps5-firmwares/" target="_blank" rel="noreferrer">download the correct PUP</a> and follow the <a href="https://www.playstation.com/en-us/support/hardware/reinstall-playstation-system-software-safe-mode" target="_blank" rel="noreferrer">official guide</a> to upgrade your PS5.</p></details><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>If you prefer a video guide, I recommend Modded Warfare&#39;s on YT. As is the nature with videos, it may not be up to date with the content here.</p></div>',6),t("iframe",{width:"560",height:"315",src:"https://www.youtube.com/embed/4Iix8SaJtaM",frameborder:"0",allow:"accelerometer; autoplay; encrypted-media; gyroscope; picture-in-picture",allowfullscreen:""},null,-1),t("h1",{id:"important-place",tabindex:"-1"},[l("Important place "),t("a",{class:"header-anchor",href:"#important-place","aria-label":'Permalink to "Important place"'},"​")],-1),t("p",null,"Here are links you will likely find usefull.",-1),t("ol",null,[t("li",null,[t("a",{href:"https://discord.gg/PeMGVB7BAm",target:"_blank",rel:"noreferrer"},"ps5-linux-discord")])],-1)])])}const w=a(s,[["render",n]]);export{h as __pageData,w as default};
